def seed_schools(db: Session) -> int:
    """插入院校种子数据（幂等：已存在的院校跳过）。

    Returns:
        新插入的院校数量
    """
    inserted = 0
    seen_names = set()
    for data in SCHOOLS:
        name, slug, code, province, level, url = data[:6]
        if name in seen_names:
            continue
        seen_names.add(name)
        ranking = data[6] if len(data) > 6 else None
        key_majors = data[7] if len(data) > 7 else None
        employment_rate = data[8] if len(data) > 8 else None
        grad_school_rate = data[9] if len(data) > 9 else None
        abroad_rate = data[10] if len(data) > 10 else None
        
        # 检查 slug 或 name 是否已存在
        existing = db.query(School).filter(
            (School.slug == slug) | (School.name == name)
        ).first()
        if existing:
            continue
        db.add(
            School(
                name=name,
                slug=slug,
                code=code,
                province=province,
                level=level,
                report_index_url=url,
                ranking=ranking,
                key_majors=key_majors,
                employment_rate=employment_rate,
                grad_school_rate=grad_school_rate,
                abroad_rate=abroad_rate,
            )
        )
        inserted += 1
    db.commit()
    return inserted
